      if(!nt.localTurn || nt.gameOver) return;
      var data=nt.getLogicData();
      if(!data||!data.p1||!data.p2||!data.s) return;
      var seat=nt.localSeat;
      if(seat!==0 && seat!==1) return;
      var fp=bestMove(flatten(data), seat);
      if(fp===null) return;
      nt.localMove({tp:0, pi:tg(fp)});
